### Step 2: Create Sidebar State Hook

<write_file>
<path>/Users/dmitry/WebstormProjects/zephyr-budget-app/client/src/hooks/useSidebar.ts</path>
<content>import { useState, useCallback } from 'react';
import type { SidebarT } from '../types/SidebarT';

const SIDEBAR_STORAGE_KEY = 'sidebar-collapsed';

export const useSidebar = (): SidebarT => {
  const [isCollapsed, setIsCollapsed] = useState<boolean>(() => {
    const stored = localStorage.getItem(SIDEBAR_STORAGE_KEY);
    return stored === 'true';
  });

  const toggleSidebar = useCallback(() => {
    setIsCollapsed((prev) => {
      const newValue = !prev;
      localStorage.setItem(SIDEBAR_STORAGE_KEY, String(newValue));
      return newValue;
    });
  }, []);

  return {
    isCollapsed,
    toggleSidebar,
  };
};
</content>
</write_file>

