### Step 3: Create Sidebar Component

<write_file>
<path>/Users/dmitry/WebstormProjects/zephyr-budget-app/client/src/components/Layout/Sidebar/Sidebar.tsx</path>
<content>import { useMemo } from 'react';
import type { SidebarT } from '../../../types/SidebarT';
import styles from './Sidebar.module.scss';

export type PropsT = {
  sidebar: SidebarT;
};

export const Sidebar = (props: PropsT) => {
  const sidebarClassName = useMemo(() => {
    return `${styles.sidebar} ${props.sidebar.isCollapsed ? styles.collapsed : ''}`;
  }, [props.sidebar.isCollapsed]);

  return (
    <aside className={sidebarClassName}>
      <div className={styles.header}>
        <button
          type="button"
          className={styles.toggleButton}
          onClick={props.sidebar.toggleSidebar}
          aria-label={props.sidebar.isCollapsed ? 'Expand sidebar' : 'Collapse sidebar'}
          aria-expanded={!props.sidebar.isCollapsed}
        >
          <span className={styles.icon}>
            {props.sidebar.isCollapsed ? '→' : '←'}
          </span>
        </button>
      </div>

      <nav className={styles.navigation} aria-label="Main navigation">
        <ul className={styles.navList}>
          <li className={styles.navItem}>
            <a href="#dashboard" className={styles.navLink}>
              <span className={styles.navIcon}>📊</span>
              {!props.sidebar.isCollapsed && (
                <span className={styles.navText}>Dashboard</span>
              )}
            </a>
          </li>
          <li className={styles.navItem}>
            <a href="#transactions" className={styles.navLink}>
              <span className={styles.navIcon}>💰</span>
              {!props.sidebar.isCollapsed && (
                <span className={styles.navText}>Transactions</span>
              )}
            </a>
          </li>
          <li className={styles.navItem}>
            <a href="#budgets" className={styles.navLink}>
              <span className={styles.navIcon}>🎯</span>
              {!props.sidebar.isCollapsed && (
                <span className={styles.navText}>Budgets</span>
              )}
            </a>
          </li>
          <li className={styles.navItem}>
            <a href="#reports" className={styles.navLink}>
              <span className={styles.navIcon}>📈</span>
              {!props.sidebar.isCollapsed && (
                <span className={styles.navText}>Reports</span>
              )}
            </a>
          </li>
        </ul>
      </nav>
    </aside>
  );
};
</content>
</write_file>

