}

.navList {
  list-style: none;
  margin: 0;
  padding: 0;
}

.navItem {
  margin: 4px 0;
}

.navLink {
  display: flex;
  align-items: center;
  padding: 12px 16px;
  color: #ffffff;
  text-decoration: none;
  transition: background-color 0.2s ease;
  gap: 12px;

  &:hover {
    background-color: #2d2d44;
  }

